const input = $input.first().json;
const host = input.host;
const apiKey = '3d3d7731d86f215abe9705716ee2b71d2cdca9cf';
const netboxUrl = 'http://10.1.1.104';

if (!host || host.trim().length === 0) {
  return { json: { exit_code: 'failed', error: 'host erforderlich' } };
}

const https = require('https');
const http = require('http');

const fetchFromNetbox = (path) => {
  return new Promise((resolve, reject) => {
    const url = new URL(path, netboxUrl);
    const client = url.protocol === 'https:' ? https : http;
    const options = {
      headers: {
        'Authorization': 'Token ' + apiKey,
        'Content-Type': 'application/json'
      }
    };
    client.get(url, options, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          resolve(JSON.parse(data));
        } catch (e) {
          resolve({ results: [] });
        }
      });
    }).on('error', reject);
  });
};

try {
  const deviceUrl = netboxUrl + '/api/dcim/devices/?q=' + encodeURIComponent(host);
  const vmUrl = netboxUrl + '/api/virtualization/virtual-machines/?q=' + encodeURIComponent(host);
  const [deviceData, vmData] = await Promise.all([
    fetchFromNetbox(deviceUrl).catch(() => ({ results: [] })),
    fetchFromNetbox(vmUrl).catch(() => ({ results: [] }))
  ]);

  let result = null;

  if (deviceData.results && deviceData.results.length > 0) {
    const device = deviceData.results[0];
    result = {
      hostname: device.name,
      ip_address: device.primary_ip?.address || device.primary_ip4?.address || host,
      ssh_user: device.custom_fields?.ssh_user || 'admin',
      ssh_password: device.custom_fields?.ssh_password || null
    };
  } else if (vmData.results && vmData.results.length > 0) {
    const vm = vmData.results[0];
    result = {
      hostname: vm.name,
      ip_address: vm.primary_ip?.address || vm.primary_ip4?.address || host,
      ssh_user: vm.custom_fields?.ssh_user || 'ubuntu',
      ssh_password: vm.custom_fields?.ssh_password || null
    };
  } else {
    result = {
      hostname: host,
      ip_address: host,
      ssh_user: 'admin',
      ssh_password: null
    };
  }

  return {
    json: {
      exit_code: result.ssh_password ? 'success' : 'partial',
      credentials: result
    }
  };
} catch (error) {
  return {
    json: {
      exit_code: 'failed',
      error: error.message
    }
  };
}
